-- STEP BOUNDARY --

-- STEP 2: query [matrikkeleneiendomskartteig]
SELECT teig.teigid, ST_AsGeoJSON(ST_Transform(teig.omrade, 4326)) AS geom_geojson FROM matrikkeleneiendomskartteig_36313fab8faa42d99cb779d86d1ca26d.teig teig WHERE teig.kommunenummer = '1103';

-- STEP BOUNDARY --

-- STEP 3: query [arealressurskart_ar50]
SELECT ST_AsGeoJSON(ST_Transform(wkb_geometry, 4326)) AS geom_geojson FROM public."0000_25833_ar50_gdb__ar50" WHERE arjordbr = 1 AND ST_Intersects(wkb_geometry, ST_Transform(ST_GeomFromGeoJSON('{"type":"MultiPolygon","coordinates":[[[[5.4,58.8],[5.4,59.1],[5.9,59.1],[5.9,58.8],[5.4,58.8]]]]}'), 25833));

